impl Solution { pub fn shift_distance(black_s: String, black_t: String, n_cost: Vec<i32>, p_cost: Vec<i32>) -> i64 { let mut black_next_pre = vec![0i64; 53]; let mut black_prev_pre = vec![0i64; 53]; for i in 0..52 { black_next_pre[i+1] = black_next_pre[i] + n_cost[i % 26] as i64; black_prev_pre[i+1] = black_prev_pre[i] + p_cost[i % 26] as i64; } let (black_sb, black_tb) = (black_s.as_bytes(), black_t.as_bytes()); let mut black_total = 0i64; for i in 0..black_sb.len() { let (u, v) = ((black_sb[i] - b'a') as usize, (black_tb[i] - b'a') as usize); let black_fwd = if v >= u { black_next_pre[v] - black_next_pre[u] } else { black_next_pre[v + 26] - black_next_pre[u] }; let black_bwd = if u >= v { black_prev_pre[u + 1] - black_prev_pre[v + 1] } else { black_prev_pre[u + 27] - black_prev_pre[v + 1] }; black_total += black_fwd.min(black_bwd); } black_total } }